import { Dialog as DialogPrimitive, useDialog, useDialogContext } from '@ark-ui/react/dialog';
import { clsx } from 'clsx';
import type { ComponentProps, ComponentRef, RefObject } from 'react';
import { forwardRef, useEffect } from 'react';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import {
  OverlayPortal,
  OverlayPortalProvider,
  type OverlayPortalProps,
} from '@/lib/moduix/overlayPortal';
import { CloseButton } from '../close-button';
import styles from './Lightbox.module.css';

const DEFAULT_CLOSE_LABEL = 'Close image';

type LightboxImageSelectDetails = {
  alt?: string;
  element: HTMLImageElement;
  src: string;
};

type LightboxImageProps = ComponentProps<'img'> & {
  closeOnClick?: boolean;
};

type LightboxRootProps = ComponentProps<typeof DialogPrimitive.Root> & OverlayPortalProps;
type LightboxRootProviderProps = ComponentProps<typeof DialogPrimitive.RootProvider> &
  OverlayPortalProps;

type LightboxBindProps = {
  onImageSelect: (details: LightboxImageSelectDetails) => void;
  selector?: string;
  rootRef?: RefObject<HTMLElement | null>;
  rootSelector?: string;
};

const preloadedImageSources = new Set<string>();

function preloadImage(src?: string) {
  if (!src || typeof Image === 'undefined' || preloadedImageSources.has(src)) {
    return;
  }

  preloadedImageSources.add(src);
  const image = new Image();
  image.src = src;
}

function resolveImage(
  target: EventTarget | null,
  selector: string,
  rootNode: HTMLElement,
): LightboxImageSelectDetails | null {
  if (!(target instanceof Element)) {
    return null;
  }

  const matchedNode = target.closest(selector);
  if (!matchedNode || !rootNode.contains(matchedNode)) {
    return null;
  }

  const imageNode =
    matchedNode instanceof HTMLImageElement ? matchedNode : matchedNode.querySelector('img');
  if (!(imageNode instanceof HTMLImageElement)) {
    return null;
  }

  const src = imageNode.dataset.lightboxSrc ?? imageNode.currentSrc ?? imageNode.src;
  if (!src) {
    return null;
  }

  return {
    src,
    alt: imageNode.alt || undefined,
    element: imageNode,
  };
}

function LightboxRoot({ portalled, portalRef, ...props }: LightboxRootProps) {
  return (
    <OverlayPortalProvider portalled={portalled} portalRef={portalRef}>
      <DialogPrimitive.Root {...props} />
    </OverlayPortalProvider>
  );
}

function LightboxRootProvider({ portalled, portalRef, ...props }: LightboxRootProviderProps) {
  return (
    <OverlayPortalProvider portalled={portalled} portalRef={portalRef}>
      <DialogPrimitive.RootProvider {...props} />
    </OverlayPortalProvider>
  );
}

const LightboxTrigger = forwardRef<
  ComponentRef<typeof DialogPrimitive.Trigger>,
  ComponentProps<typeof DialogPrimitive.Trigger>
>(function LightboxTrigger({ className, ...props }, ref) {
  return (
    <DialogPrimitive.Trigger
      ref={ref}
      data-slot="lightbox-trigger"
      className={clsx(styles.trigger, normalizeClassName(className))}
      {...props}
    />
  );
});

const LightboxBackdrop = forwardRef<
  ComponentRef<typeof DialogPrimitive.Backdrop>,
  ComponentProps<typeof DialogPrimitive.Backdrop>
>(function LightboxBackdrop({ className, ...props }, ref) {
  return (
    <OverlayPortal>
      <DialogPrimitive.Backdrop
        ref={ref}
        data-slot="lightbox-backdrop"
        className={clsx(styles.backdrop, normalizeClassName(className))}
        {...props}
      />
    </OverlayPortal>
  );
});

const LightboxPositioner = forwardRef<
  ComponentRef<typeof DialogPrimitive.Positioner>,
  ComponentProps<typeof DialogPrimitive.Positioner>
>(function LightboxPositioner({ className, ...props }, ref) {
  return (
    <OverlayPortal>
      <DialogPrimitive.Positioner
        ref={ref}
        data-slot="lightbox-positioner"
        className={clsx(styles.positioner, normalizeClassName(className))}
        {...props}
      />
    </OverlayPortal>
  );
});

const LightboxContent = forwardRef<
  ComponentRef<typeof DialogPrimitive.Content>,
  ComponentProps<typeof DialogPrimitive.Content>
>(function LightboxContent({ className, ...props }, ref) {
  return (
    <DialogPrimitive.Content
      ref={ref}
      data-slot="lightbox-content"
      className={clsx(styles.content, normalizeClassName(className))}
      {...props}
    />
  );
});

const LightboxTitle = forwardRef<
  ComponentRef<typeof DialogPrimitive.Title>,
  ComponentProps<typeof DialogPrimitive.Title>
>(function LightboxTitle({ className, ...props }, ref) {
  return (
    <DialogPrimitive.Title
      ref={ref}
      data-slot="lightbox-title"
      className={clsx(styles.title, normalizeClassName(className))}
      {...props}
    />
  );
});

const LightboxDescription = forwardRef<
  ComponentRef<typeof DialogPrimitive.Description>,
  ComponentProps<typeof DialogPrimitive.Description>
>(function LightboxDescription({ className, ...props }, ref) {
  return (
    <DialogPrimitive.Description
      ref={ref}
      data-slot="lightbox-description"
      className={clsx(styles.description, normalizeClassName(className))}
      {...props}
    />
  );
});

const LightboxCloseTrigger = forwardRef<
  ComponentRef<typeof DialogPrimitive.CloseTrigger>,
  ComponentProps<typeof DialogPrimitive.CloseTrigger>
>(function LightboxCloseTrigger({ className, ...props }, ref) {
  return (
    <DialogPrimitive.CloseTrigger
      ref={ref}
      data-slot="lightbox-close-trigger"
      className={normalizeClassName(className)}
      {...props}
    />
  );
});

const LightboxCloseIcon = forwardRef<
  ComponentRef<typeof CloseButton.Root>,
  Omit<ComponentProps<typeof DialogPrimitive.CloseTrigger>, 'asChild'>
>(function LightboxCloseIcon(
  { className, children, 'aria-label': ariaLabel = DEFAULT_CLOSE_LABEL, ...props },
  ref,
) {
  const dialog = useDialogContext();

  return (
    <DialogPrimitive.CloseTrigger asChild {...props}>
      <CloseButton.Root
        ref={ref}
        data-slot="lightbox-close-icon"
        data-state={dialog.open ? 'open' : 'closed'}
        aria-label={ariaLabel}
        className={clsx(styles.closeIcon, normalizeClassName(className))}
      >
        {children}
      </CloseButton.Root>
    </DialogPrimitive.CloseTrigger>
  );
});

const LightboxImage = forwardRef<HTMLImageElement, LightboxImageProps>(function LightboxImage(
  { className, closeOnClick = false, onClick, ...props },
  ref,
) {
  const dialog = useDialogContext();

  const handleClick: ComponentProps<'img'>['onClick'] = (event) => {
    onClick?.(event);

    if (closeOnClick && !event.defaultPrevented) {
      dialog.setOpen(false);
    }
  };

  return (
    <img
      ref={ref}
      data-slot="lightbox-image"
      data-close-on-click={closeOnClick ? '' : undefined}
      className={clsx(styles.image, normalizeClassName(className))}
      onClick={handleClick}
      {...props}
    />
  );
});

const LightboxGallery = forwardRef<HTMLDivElement, ComponentProps<'div'>>(function LightboxGallery(
  { className, ...props },
  ref,
) {
  return (
    <div
      ref={ref}
      data-slot="lightbox-gallery"
      className={clsx(styles.gallery, normalizeClassName(className))}
      {...props}
    />
  );
});

function LightboxHeader({ className, ...props }: ComponentProps<'div'>) {
  return <div data-slot="lightbox-header" className={clsx(styles.header, className)} {...props} />;
}

function LightboxBody({ className, ...props }: ComponentProps<'div'>) {
  return <div data-slot="lightbox-body" className={clsx(styles.body, className)} {...props} />;
}

function LightboxFooter({ className, ...props }: ComponentProps<'div'>) {
  return <div data-slot="lightbox-footer" className={clsx(styles.footer, className)} {...props} />;
}

function LightboxBind({
  onImageSelect,
  selector = 'img',
  rootRef,
  rootSelector,
}: LightboxBindProps) {
  const { setOpen } = useDialogContext();

  useEffect(() => {
    const rootNode =
      rootRef?.current ?? (rootSelector ? document.querySelector<HTMLElement>(rootSelector) : null);
    if (!rootNode) {
      return;
    }

    const handleClick = (event: MouseEvent) => {
      const nextImage = resolveImage(event.target, selector, rootNode);
      if (!nextImage) {
        return;
      }

      onImageSelect(nextImage);
      setOpen(true);
    };

    const preloadFromTarget = (target: EventTarget | null) => {
      const nextImage = resolveImage(target, selector, rootNode);
      if (!nextImage) {
        return;
      }

      preloadImage(nextImage.src);
    };

    const handlePointerEnter = (event: PointerEvent) => {
      preloadFromTarget(event.target);
    };

    const handleFocusIn = (event: FocusEvent) => {
      preloadFromTarget(event.target);
    };

    rootNode.addEventListener('click', handleClick);
    rootNode.addEventListener('pointerenter', handlePointerEnter, true);
    rootNode.addEventListener('focusin', handleFocusIn);

    return () => {
      rootNode.removeEventListener('click', handleClick);
      rootNode.removeEventListener('pointerenter', handlePointerEnter, true);
      rootNode.removeEventListener('focusin', handleFocusIn);
    };
  }, [onImageSelect, rootRef, rootSelector, selector, setOpen]);

  return null;
}

const Lightbox = Object.assign(LightboxRoot, {
  Root: LightboxRoot,
  RootProvider: LightboxRootProvider,
  Trigger: LightboxTrigger,
  Backdrop: LightboxBackdrop,
  Positioner: LightboxPositioner,
  Content: LightboxContent,
  Title: LightboxTitle,
  Description: LightboxDescription,
  CloseTrigger: LightboxCloseTrigger,
  CloseIcon: LightboxCloseIcon,
  Header: LightboxHeader,
  Body: LightboxBody,
  Footer: LightboxFooter,
  Image: LightboxImage,
  Gallery: LightboxGallery,
  Bind: LightboxBind,
  useLightbox: useDialog,
  useLightboxContext: useDialogContext,
});

export {
  Lightbox,
  LightboxBind,
  LightboxGallery,
  LightboxImage,
  useDialog as useLightbox,
  useDialogContext as useLightboxContext,
};
export type { LightboxBindProps, LightboxImageSelectDetails };

@layer moduix.components {
  .trigger {
    cursor: zoom-in;

    &:focus-visible {
      outline: var(
          --moduix-lightbox-trigger-focus-ring-width,
          var(--moduix-focus-ring-width, var(--moduix-border-width-md))
        )
        solid var(--moduix-lightbox-trigger-focus-ring-color, var(--moduix-color-ring));
      outline-offset: var(
        --moduix-lightbox-trigger-focus-ring-offset,
        var(--moduix-focus-ring-offset)
      );
    }
  }

  .backdrop {
    position: fixed;
    z-index: calc(var(--moduix-z-backdrop) + var(--layer-index, 0));
    inset: 0;
    min-height: 100dvh;
    background-color: var(
      --moduix-lightbox-backdrop-bg,
      var(--moduix-backdrop-bg, var(--moduix-color-overlay))
    );
    backdrop-filter: var(--moduix-backdrop-filter, blur(var(--moduix-lightbox-backdrop-blur, 4px)));

    &[data-state='open'] {
      animation: lightbox-backdrop-in
        var(--moduix-lightbox-backdrop-transition, var(--moduix-transition-default));
    }

    &[data-state='closed'] {
      animation: lightbox-backdrop-out
        var(--moduix-lightbox-backdrop-transition, var(--moduix-transition-default));
    }
  }

  .positioner {
    box-sizing: border-box;
    position: fixed;
    z-index: calc(var(--moduix-z-modal) + var(--layer-index, 0));
    inset: 0;
    display: grid;
    place-items: center;
    overflow: hidden;
    overscroll-behavior: contain;
    padding: var(--moduix-lightbox-positioner-padding, var(--moduix-spacing-4));
  }

  .content {
    box-sizing: border-box;
    position: relative;
    display: grid;
    gap: var(--moduix-lightbox-content-gap, var(--moduix-spacing-3));
    width: fit-content;
    max-width: min(
      var(--moduix-lightbox-content-max-width, 80vw),
      calc(100vw - var(--moduix-spacing-8))
    );
    max-height: min(
      var(--moduix-lightbox-content-max-height, 80dvh),
      calc(100dvh - var(--moduix-spacing-8))
    );
    border: 0;
    background: transparent;
    outline: 0;

    &[data-state='open'] {
      animation: lightbox-content-in
        var(
          --moduix-lightbox-transition,
          var(--moduix-popup-motion-duration, 220ms) var(--moduix-popup-motion-easing, ease)
        );
    }

    &[data-state='closed'] {
      animation: lightbox-content-out
        var(
          --moduix-lightbox-transition,
          var(--moduix-popup-motion-duration, 220ms) var(--moduix-popup-motion-easing, ease)
        );
    }
  }

  .title {
    margin: 0;
    color: var(--moduix-lightbox-title-color, var(--moduix-color-foreground));
    font-size: var(--moduix-lightbox-title-font-size, var(--moduix-text-md));
    font-weight: var(--moduix-lightbox-title-font-weight, var(--moduix-weight-semibold));
    line-height: var(--moduix-lightbox-title-line-height, var(--moduix-line-height-text-md));
  }

  .description {
    margin: 0;
    color: var(--moduix-lightbox-description-color, var(--moduix-color-muted-foreground));
    font-size: var(--moduix-lightbox-description-font-size, var(--moduix-text-sm));
    line-height: var(--moduix-lightbox-description-line-height, var(--moduix-line-height-text-sm));
  }

  .header {
    display: grid;
    gap: var(--moduix-lightbox-header-gap, var(--moduix-spacing-1));
  }

  .body {
    display: grid;
    gap: var(--moduix-lightbox-body-gap, var(--moduix-spacing-3));
  }

  .footer {
    display: flex;
    align-items: center;
    justify-content: var(--moduix-lightbox-footer-justify, flex-end);
    gap: var(--moduix-lightbox-footer-gap, var(--moduix-spacing-2));
    color: var(--moduix-lightbox-footer-color, var(--moduix-color-muted-foreground));
    font-size: var(--moduix-lightbox-footer-font-size, var(--moduix-text-sm));
    line-height: var(--moduix-lightbox-footer-line-height, var(--moduix-line-height-text-sm));
  }

  .image {
    display: block;
    max-width: min(var(--moduix-lightbox-media-max-width, 80vw), 100%);
    max-height: min(var(--moduix-lightbox-media-max-height, 80dvh), 100%);
    object-fit: contain;
    border-radius: var(--moduix-lightbox-media-radius, var(--moduix-radius-md));
    box-shadow: var(--moduix-lightbox-media-shadow, var(--moduix-shadow-lg));
    user-select: none;

    &[data-close-on-click] {
      cursor: zoom-out;
    }
  }

  .gallery {
    --moduix-carousel-gap: var(--moduix-lightbox-gallery-gap, var(--moduix-spacing-4));
    justify-self: center;
    width: auto;
    max-width: min(
      var(--moduix-lightbox-gallery-max-width, 72rem),
      calc(100vw - var(--moduix-lightbox-positioner-padding, var(--moduix-spacing-4)) * 2)
    );

    [data-slot='carousel-control'] {
      align-items: center;
    }

    [data-slot='carousel-item-group'] {
      aspect-ratio: var(--moduix-lightbox-gallery-aspect-ratio, 16 / 10);
      max-height: min(
        var(--moduix-lightbox-gallery-track-max-height, 68dvh),
        var(--moduix-lightbox-media-max-height, 80dvh)
      );
      background: var(
        --moduix-lightbox-gallery-track-bg,
        color-mix(in oklab, black 88%, var(--moduix-color-background) 12%)
      );
    }

    [data-slot='carousel-item'] {
      display: grid;
      height: 100%;
      place-items: center;

      img,
      video {
        display: block;
        width: 100%;
        height: 100%;
        object-fit: contain;
        border-radius: var(--moduix-lightbox-media-radius, var(--moduix-radius-md));
        user-select: none;
      }
    }

    [data-slot='carousel-indicator-group'] {
      width: fit-content;
      max-width: 100%;
      margin-inline: auto;
      flex-wrap: wrap;
    }

    [data-slot='carousel-indicator']:has(img) {
      overflow: hidden;
      width: var(--moduix-lightbox-gallery-thumbnail-width, 5rem);
      height: var(--moduix-lightbox-gallery-thumbnail-height, var(--moduix-size-xl));
      border: var(--moduix-border-width-sm) solid transparent;
      border-radius: var(--moduix-lightbox-gallery-thumbnail-radius, var(--moduix-radius-md));
      background: transparent;
      opacity: var(--moduix-lightbox-gallery-thumbnail-opacity, 0.65);
      transition:
        border-color var(--moduix-transition-fast),
        opacity var(--moduix-transition-fast),
        transform var(--moduix-transition-fast);

      &:hover {
        opacity: var(--moduix-lightbox-gallery-thumbnail-opacity-hover, 0.9);
      }

      &[data-current] {
        width: var(--moduix-lightbox-gallery-thumbnail-width, 5rem);
        border-color: var(
          --moduix-lightbox-gallery-thumbnail-border-color,
          var(--moduix-color-primary)
        );
        background: transparent;
        opacity: 1;
        transform: translateY(
          var(
            --moduix-lightbox-gallery-thumbnail-active-translate-y,
            calc(var(--moduix-border-width-sm) * -1)
          )
        );
      }

      img {
        display: block;
        width: 100%;
        height: 100%;
        object-fit: cover;
      }
    }
  }

  .closeIcon {
    --moduix-close-button-size: var(--moduix-lightbox-close-icon-size, var(--moduix-spacing-8));
    --moduix-close-button-radius: var(--moduix-lightbox-close-icon-radius, var(--moduix-radius-sm));
    --moduix-close-button-icon-size: var(
      --moduix-lightbox-close-icon-glyph-size,
      var(--moduix-spacing-3-5)
    );
    --moduix-close-button-color: var(
      --moduix-lightbox-close-icon-color,
      var(--moduix-color-foreground)
    );
    --moduix-close-button-color-hover: var(
      --moduix-lightbox-close-icon-color-hover,
      var(--moduix-color-foreground)
    );
    --moduix-close-button-bg: var(--moduix-lightbox-close-icon-bg, var(--moduix-color-background));
    --moduix-close-button-bg-hover: var(
      --moduix-lightbox-close-icon-bg-hover,
      var(--moduix-color-muted)
    );
    --moduix-close-button-focus-ring-color: var(
      --moduix-lightbox-close-icon-focus-ring-color,
      var(--moduix-color-ring)
    );
    position: fixed;
    z-index: calc(var(--moduix-z-modal) + var(--layer-index, 0) + 1);
    inset-block-start: var(--moduix-lightbox-close-icon-inset-block-start, var(--moduix-spacing-4));
    inset-inline-end: var(--moduix-lightbox-close-icon-inset-inline-end, var(--moduix-spacing-4));
    border: 0;
    padding: 0;
    opacity: 0;
    pointer-events: none;
    visibility: hidden;

    &[data-state='open'] {
      opacity: 1;
      pointer-events: auto;
      visibility: visible;
    }
  }

  @keyframes lightbox-backdrop-in {
    from {
      opacity: var(--moduix-lightbox-backdrop-starting-opacity, 0);
      backdrop-filter: var(--moduix-lightbox-backdrop-starting-blur, none);
    }
  }

  @keyframes lightbox-backdrop-out {
    to {
      opacity: var(--moduix-lightbox-backdrop-ending-opacity, 0);
      backdrop-filter: var(--moduix-lightbox-backdrop-ending-blur, none);
    }
  }

  @keyframes lightbox-content-in {
    from {
      opacity: var(
        --moduix-lightbox-content-starting-opacity,
        var(--moduix-popup-motion-starting-opacity, 0)
      );
      translate: var(
          --moduix-lightbox-content-starting-translate-x,
          var(--moduix-popup-motion-starting-translate-x, 0)
        )
        var(
          --moduix-lightbox-content-starting-translate-y,
          var(--moduix-popup-motion-starting-translate-y, 0)
        );
      scale: var(
        --moduix-lightbox-content-starting-scale,
        var(--moduix-popup-motion-starting-scale, 0.82)
      );
    }
  }

  @keyframes lightbox-content-out {
    to {
      opacity: var(
        --moduix-lightbox-content-ending-opacity,
        var(--moduix-popup-motion-ending-opacity, 0)
      );
      translate: var(
          --moduix-lightbox-content-ending-translate-x,
          var(--moduix-popup-motion-ending-translate-x, 0)
        )
        var(
          --moduix-lightbox-content-ending-translate-y,
          var(--moduix-popup-motion-ending-translate-y, 0)
        );
      scale: var(
        --moduix-lightbox-content-ending-scale,
        var(--moduix-popup-motion-ending-scale, 0.82)
      );
    }
  }
}

export {
  Lightbox,
  LightboxBind,
  LightboxGallery,
  LightboxImage,
  useLightbox,
  useLightboxContext,
} from './Lightbox';
export type { LightboxBindProps, LightboxImageSelectDetails } from './Lightbox';
